            //btnReports = new Guna.UI2.WinForms.Guna2Button();
            lblLogo = new Guna.UI2.WinForms.Guna2HtmlLabel();

            SuspendLayout();

            // sidebarPanel
            sidebarPanel.Dock = DockStyle.Left;
            sidebarPanel.Width = 250;
            sidebarPanel.FillColor = Color.FromArgb(39, 38, 97);
            sidebarPanel.Controls.Add(lblLogo);
            sidebarPanel.Controls.Add(btnDashboard);
            //sidebarPanel.Controls.Add(btnFleet);
            //sidebarPanel.Controls.Add(btnReports);

            // lblLogo
            lblLogo.Text = "<b style='color:white; font-size: 16px; font-family: Segoe UI;'>AutoRent</b><br><span style='color:#aeb2cc; font-size:10px; font-family: Segoe UI;'>Admin Panel</span>";
            lblLogo.Location = new Point(20, 20);
            lblLogo.BackColor = Color.Transparent;

            // btnDashboard
            btnDashboard.Text = "Dashboard";
            btnDashboard.FillColor = Color.FromArgb(59, 57, 128); // Active state
            btnDashboard.ForeColor = Color.White;
            btnDashboard.Location = new Point(10, 80);
            btnDashboard.Size = new Size(230, 45);
            btnDashboard.BorderRadius = 8;
            btnDashboard.TextAlign = HorizontalAlignment.Left;
            btnDashboard.TextOffset = new Point(15, 0);

            // btnFleet
            //btnFleet.Text = "Fleet";
            //btnFleet.FillColor = Color.Transparent;
            //btnFleet.ForeColor = Color.FromArgb(174, 178, 204);
            //btnFleet.Location = new Point(10, 130);
            //btnFleet.Size = new Size(230, 45);
            //btnFleet.BorderRadius = 8;
            //btnFleet.TextAlign = HorizontalAlignment.Left;
            //btnFleet.TextOffset = new Point(15, 0);

            //// btnReports
            //btnReports.Text = "Reports";
            //btnReports.FillColor = Color.Transparent;
            //btnReports.ForeColor = Color.FromArgb(174, 178, 204);
            //btnReports.Location = new Point(10, 180);
            //btnReports.Size = new Size(230, 45);
            //btnReports.BorderRadius = 8;
            //btnReports.TextAlign = HorizontalAlignment.Left;
            //btnReports.TextOffset = new Point(15, 0);

            // headerPanel
            headerPanel.Dock = DockStyle.Top;
            headerPanel.Height = 70;
            headerPanel.FillColor = Color.White;
            headerPanel.CustomBorderColor = Color.FromArgb(235, 236, 239);
            headerPanel.CustomBorderThickness = new Padding(0, 0, 0, 1);

            // mainPanel
            mainPanel.Dock = DockStyle.Fill;
            mainPanel.FillColor = Color.FromArgb(245, 246, 250);

            Controls.Add(mainPanel);
            Controls.Add(headerPanel);
            Controls.Add(sidebarPanel);

            ResumeLayout(false);
        }

